{
  "evaluation_of_each_diagnosis": {
    "Embryonal rhabdomyosarcoma": {
      "supporting": "Young age, progressive enlarging mass, failure to heal after drainage, friable necrotic tissue, lack of systemic infection signs.",
      "against": "Rare in the oropharynx, though possible.",
      "support_level": "Well-supported"
    },
    "Non-Hodgkin lymphoma": {
      "supporting": "Rapidly growing oropharyngeal mass, persistent symptoms, minimal systemic signs.",
      "against": "Typically associated with lymphadenopathy, though primary extranodal presentation occurs.",
      "support_level": "Well-supported"
    },
    "Pleomorphic adenoma of minor salivary gland": {
      "supporting": "Location in the soft palate/peritonsillar area.",
      "against": "Clinical behavior is too aggressive; typically presents as a slow-growing, painless mass. Does not explain friability or spontaneous bleeding.",
      "support_level": "Weakly supported"
    },
    "Carcinoma ex pleomorphic adenoma": {
      "supporting": "Can present with rapid enlargement and invasive behavior.",
      "against": "Typically seen in older patients with a long-standing history of a mass.",
      "support_level": "Weakly supported"
    },
    "Granulomatosis with polyangiitis": {
      "supporting": "Ulceration, necrotic tissue, failure to respond to antibiotics.",
      "against": "No systemic signs (no sinus, pulmonary, or renal involvement).",
      "support_level": "Weakly supported"
    },
    "Vascular malformation or pseudoaneurysm": {
      "supporting": "Repetitive bleeding, sanguineous drainage.",
      "against": "Does not explain the solid mass appearance on CT.",
      "support_level": "Weakly supported"
    },
    "Infected branchial cleft cyst": {
      "supporting": "Fluctuance, drainage history.",
      "against": "Failure to resolve despite surgical drainage and multiple courses of antibiotics.",
      "support_level": "Weakly supported"
    }
  },
  "missing_diagnoses": [
    "Carotid artery pseudoaneurysm (as a primary vascular catastrophe masking as a mass)",
    "Extramedullary plasmacytoma",
    "Sinonasal-type undifferentiated carcinoma"
  ],
